// ============================================================================
// HELPER FUNCTIONS
// ============================================================================

export const getReadinessColor = (level: ReadinessLevel): string => {
  switch (level) {
    case 'High': return '#10B981';
    case 'Medium': return '#FB923C';
    case 'Low': return '#FD4438';
  }
};

export const getPillarColor = (score: PillarScore): string => {
  if (score >= 4) return '#10B981';  // Green - stable
  if (score >= 2) return '#FB923C';  // Yellow - fix soon
  return '#FD4438';  // Red - urgent
};

export const getStatusColor = (status: LeadStatus): { bg: string; text: string; border: string } => {
  switch (status) {
    case 'new':
      return { bg: '#8B5CF6', text: '#F5F5FF', border: '#8B5CF6' };
    case 'needs-review':
      return { bg: '#FB923C', text: '#FFF', border: '#FB923C' };
    case 'ready-for-call':
      return { bg: '#3B82F6', text: '#FFF', border: '#3B82F6' };
    case 'proposal-sent':
      return { bg: '#06D7F6', text: '#0A0A0F', border: '#06D7F6' };
    case 'converted':
      return { bg: '#10B981', text: '#FFF', border: '#10B981' };
    case 'disqualified':
      return { bg: '#70707C', text: '#FFF', border: '#70707C' };
    default:
      // Fallback for any unexpected status values
      return { bg: '#8B5CF6', text: '#F5F5FF', border: '#8B5CF6' };
  }
};

export const getServiceLabel = (service: ServiceType): string => {
  switch (service) {
    case 'operations-audit': return 'Operations Audit';
    case 'ai-implementation': return 'AI Implementation';
    case 'automation-sprint': return 'Automation Sprint';
    case 'systems-integration': return 'Systems Integration';
    case 'strategic-roadmap': return 'Strategic Roadmap';
    case 'founder-leverage': return 'Founder Leverage Package';
  }
};

/**
 * API INTEGRATION POINTS
 *
 * Backend endpoints needed:
 *
 * GET /api/cortex/leads
 * - Returns: Lead[]
 * - Purpose: Get all leads with basic info
 *
 * GET /api/cortex/lead/:id
 * - Returns: CortexLeadData
 * - Purpose: Get complete data for one lead
 *
 * POST /api/cortex/analyze/:submissionId
 * - Body: { submissionId: string }
 * - Returns: CortexLeadData
 * - Purpose: Trigger AI analysis of a new submission
 *
 * PUT /api/cortex/lead/:id/status
 * - Body: { status: LeadStatus, reason: string }
 * - Returns: { success: boolean }
 * - Purpose: Update lead status
 *
 * PUT /api/cortex/lead/:id/recommendation
 * - Body: { status: RecommendationStatus, overrideReason?: string }
 * - Returns: { success: boolean }
 * - Purpose: Accept/modify/override AI recommendation
 *
 * POST /api/cortex/lead/:id/proposal
 * - Body: ProposalData
 * - Returns: { success: boolean, proposalUrl: string }
 * - Purpose: Generate and save proposal
 *
 * POST /api/cortex/lead/:id/feedback
 * - Body: OutcomeFeedback
 * - Returns: { success: boolean }
 * - Purpose: Log outcome for learning loop
 *
 * GET /api/cortex/insights
 * - Returns: LearningInsights
 * - Purpose: Get system-wide learning insights
 */

