// ============================================================================
// CONTRACT AUTO-GENERATION — Phase 6
// ============================================================================

export type ContractStatus = 'draft' | 'sent' | 'signed';
export type PaymentStructure = 'upfront_milestone' | 'fixed_fee' | 'retainer';

export interface ContractDeliverable {
  deliverable_id: string;
  solution_id:    string;
  title:          string;
  description:    string;
  acceptance_criteria: string[];
}

export interface ContractMilestone {
  milestone_id:       string;
  phase_number:       number;
  title:              string;
  duration_weeks:     number;
  payment_percentage: number;   // % of total due at this milestone
  deliverable_ids:    string[];
}

export interface PaymentScheduleItem {
  label:       string;
  amount:      number;
  due_trigger: string;
  percentage:  number;
}

export interface LegalBlock {
  id:      string;
  title:   string;
  text:    string;
  editable: false;
}

export interface ContractPayload {
  contract_id:              string;
  proposal_id:              string;
  generated_at:             string;
  client_legal_name:        string;
  engagement_scope:         ContractDeliverable[];
  exclusions:               string[];
  milestones:               ContractMilestone[];
  investment:               number;
  currency:                 string;
  payment_structure:        PaymentStructure;
  payment_terms:            string;
  payment_schedule:         PaymentScheduleItem[];
  liability_limits:         string;
  confidentiality_clause:   true;
  data_protection_clause:   true;
  termination_clause:       string;
  signature_required:       true;
  legal_blocks:             LegalBlock[];
  status:                   ContractStatus;
  sent_at:                  string | null;
  signed_at:                string | null;
  kickoff_triggered:        boolean;
  /** Snapshot of portfolio_version_id at generation time — used to detect ROI drift */
  roi_version_snapshot?:    string;
}

// ============================================================================
// OBJECTION HANDLING INTELLIGENCE — Phase 6
// ============================================================================

export type ObjectionType = 'price' | 'risk' | 'timing' | 'trust' | 'internal_alignment';

export interface ObjectionDetected {
  type:       ObjectionType;
  confidence: number;   // 0.0–1.0
  at_risk:    boolean;  // confidence > 0.7
}

export interface ObjectionPlaybook {
  type:            ObjectionType;
  label:           string;
  response_points: string[];
  email_subject:   string;
  email_body:      string;
}

// ============================================================================
// CRM SYNCHRONIZATION LAYER — Phase 7
// Spec: crm-sync-spec.md
// ============================================================================

/** 14 locked canonical pipeline stages */
export type CRMStage =
  | 'lead_captured'
  | 'diagnostic_started'
  | 'diagnostic_completed'
  | 'proposal_draft'
  | 'proposal_sent'
  | 'proposal_viewed'
  | 'negotiation_objection'
  | 'approved_pending_contract'
  | 'contract_sent'
  | 'contract_signed'
  | 'onboarding_started'
  | 'implementation_active'
  | 'closed_won'
  | 'closed_lost';

/** All event types that can trigger a CRM sync */
export type CRMActivityType =
  | 'deal_created'
  | 'diagnostic_started'
  | 'diagnostic_completed'
  | 'proposal_created'
  | 'proposal_ready_to_send'
  | 'proposal_sent'
  | 'proposal_viewed'
  | 'objection_detected'
  | 'proposal_approved'
  | 'proposal_rejected'
  | 'contract_generated'
  | 'contract_sent'
  | 'contract_signed'
  | 'onboarding_started'
  | 'implementation_started'
  | 'project_completed';

export interface CRMActivityLog {
  activity_id: string;
  deal_id:     string;
  type:        CRMActivityType;
  /** Arbitrary JSON payload — proposal_id, timestamps, confidence, etc. */
  payload:     Record<string, unknown>;
  created_at:  string;
}

export type CRMTaskStatus = 'open' | 'done';

export interface CRMTask {
  task_id:     string;
  deal_id:     string;
  assigned_to: string;
  task_type:   string;
  due_at:      string;   // ISO date
  status:      CRMTaskStatus;
  notes:       string;
  /** Derived at render time — not stored */
  overdue?:    boolean;
}

export interface CRMDeal {
  deal_id:           string;
  client_id:         string;
  proposal_id:       string | null;
  contract_id:       string | null;
  owner_user_id:     string;
  stage:             CRMStage;
  value_estimate:    number;
  close_probability: number;   // 0–1
  created_at:        string;
  updated_at:        string;
  activity:          CRMActivityLog[];
  tasks:             CRMTask[];
}

// ============================================================================
// POST-IMPLEMENTATION ROI TRACKING ENGINE — Phase 8
// Spec: roi-tracking-spec.md
// ============================================================================

export type BaselineQuality = 'low' | 'medium' | 'high';

/** 9 locked variance reason tags from spec §5 */
export type VarianceReasonTag =
  | 'adoption_delay'
  | 'data_quality_issue'
  | 'scope_change'
  | 'integration_blocker'
  | 'stakeholder_bottleneck'
  | 'tool_limitations'
  | 'model_performance'
  | 'underestimated_change_mgmt'
  | 'positive_outlier';

/** Baseline metrics snapshot — captured at contract_signed / onboarding_started */
export interface BaselineMetrics {
  ticket_volume_per_week:        number;
  response_time_hours:           number;   // avg ticket / query response
  admin_hours_per_week:          number;
  lead_response_time_hours:      number;
  conversion_rate_pct:           number;   // 0–100
  proposal_cycle_days:           number;
  tool_costs_monthly:            number;   // $
  headcount_involved:            number;
}

/** roi_baselines record — Spec §1 */
export interface ROIBaseline {
  baseline_id:          string;
  deal_id:              string;
  proposal_id:          string;
  portfolio_version_id: string;
  captured_at:          string;
  metrics_snapshot:     BaselineMetrics;
  baseline_quality:     BaselineQuality;
  notes:                string;
}

/** roi_actuals record — one row per month — Spec §1 + §3 */
export interface ROIActualsEntry {
  actual_id:               string;
  deal_id:                 string;
  period_start:            string;   // YYYY-MM-01
  period_end:              string;   // YYYY-MM-last
  period_label:            string;   // "Month 1", "Month 2"
  metrics: {
    actual_monthly_gain:       number;
    actual_monthly_investment: number;
    net_actual:                number;
    cumulative_actual:         number;
  };
  notes:                   string;
  captured_by:             string;
  created_at:              string;
}

/** roi_variance record — one row per period — Spec §4 */
export interface ROIVariance {
  variance_id:            string;
  deal_id:                string;
  period:                 string;
  period_label:           string;
  projected: {
    monthly_gain:         number;
    monthly_investment:   number;
    cumulative:           number;
  };
  actual: {
    monthly_gain:         number;
    monthly_investment:   number;
    cumulative:           number;
  };
  delta: {
    variance_gain:              number;   // actual - projected
    variance_pct:               number;   // %
    variance_payback_shift:     number;   // months shifted (+ = delay, - = accelerated)
  };
  variance_reason_tags:   VarianceReasonTag[];
}

/** roi_solution_attribution record — Spec §1 */
export interface ROISolutionAttribution {
  deal_id:                    string;
  solution_id:                string;
  solution_title:             string;
  period:                     string;
  projected_gain:             number;
  actual_gain:                number;
  confidence_adjusted_actual: number;
  realization_factor:         number;   // actual / projected; < 1 = under, > 1 = over
  notes:                      string;
}

/** Rolled-up realization factors per industry — Spec §6 */
export interface RealizationFactorRecord {
  industry:                   string;
  efficiency_realization_actual: number;
  revenue_realization_actual:    number;
  sample_count:               number;
  last_updated_at:            string;
}